## mylib — Example Nim FFI API library using nim-brokers
## =====================================================
## Demonstrates how to build a Nim dynamic library with C-callable
## interfaces generated by the broker FFI API system.
##
## Build:
##   nim c -d:BrokerFfiApi --threads:on --app:lib --path:../../../src \
##     --outdir:build mylib.nim
##
## Produces: build/libmylib.{so,dylib,dll} + mylib.h

{.push raises: [].}

import brokers/[event_broker, request_broker, broker_context]

when defined(BrokerFfiApi):
  import brokers/api_library

# ---------------------------------------------------------------------------
# Request Brokers (functional API)
# ---------------------------------------------------------------------------

## InitRequest: called after mylib_init() to initialize library state.
## Takes a configuration path, returns init status.
RequestBroker(API):
  type InitRequest = object
    configPath*: string
    initialized*: bool

  proc signature*(configPath: string): Future[Result[InitRequest, string]] {.async.}

## DestroyRequest: called before mylib_shutdown() to clean up library state.
RequestBroker(API):
  type DestroyRequest = object
    status*: int32

  proc signature*(): Future[Result[DestroyRequest, string]] {.async.}

## GetStatus: query the current health/status of the library.
RequestBroker(API):
  type GetStatus = object
    healthy*: bool
    uptimeMs*: int64
    message*: string

  proc signature*(): Future[Result[GetStatus, string]] {.async.}

# ---------------------------------------------------------------------------
# Event Brokers (proactive API)
# ---------------------------------------------------------------------------

## StatusChanged: emitted when the library's health status changes.
EventBroker(API):
  type StatusChanged = object
    healthy*: bool
    message*: string

# ---------------------------------------------------------------------------
# Library internals (provider implementations)
# ---------------------------------------------------------------------------

var gLibStartTimeMs {.threadvar.}: int64
var gLibHealthy {.threadvar.}: bool
var gLibConfigPath {.threadvar.}: string

proc setupProviders(ctx: BrokerContext) =
  ## Set up broker providers on the library's processing thread.
  ## Called once after the thread starts and adopts the broker context.

  # InitRequest provider
  discard InitRequest.setProvider(
    ctx,
    proc(configPath: string): Future[Result[InitRequest, string]] {.closure, async.} =
      gLibConfigPath = configPath
      gLibHealthy = true
      gLibStartTimeMs = int64(chronos.Moment.now().epochNanoSeconds div 1_000_000)
      return ok(InitRequest(configPath: configPath, initialized: true)),
  )

  # DestroyRequest provider
  discard DestroyRequest.setProvider(
    ctx,
    proc(): Future[Result[DestroyRequest, string]] {.closure, async.} =
      gLibHealthy = false
      # Emit a status change event
      await StatusChanged.emit(
        ctx, StatusChanged(healthy: false, message: "Library shutting down")
      )
      return ok(DestroyRequest(status: 0)),
  )

  # GetStatus provider
  discard GetStatus.setProvider(
    ctx,
    proc(): Future[Result[GetStatus, string]] {.closure, async.} =
      let now = int64(chronos.Moment.now().epochNanoSeconds div 1_000_000)
      let uptime = now - gLibStartTimeMs
      return ok(
        GetStatus(
          healthy: gLibHealthy,
          uptimeMs: uptime,
          message:
            if gLibHealthy:
              "Running with config: " & gLibConfigPath
            else:
              "Not initialized",
        )
      ),
  )

# ---------------------------------------------------------------------------
# Library registration — MUST be last
# ---------------------------------------------------------------------------

when defined(BrokerFfiApi):
  registerBrokerLibrary:
    name:
      "mylib"
    initRequest:
      InitRequest
    destroyRequest:
      DestroyRequest

{.pop.}
